import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = ({ isAuthenticated, activeMenu, setActiveMenu, handleLogout }) => {
    return (
        <nav style={{ padding: '20px 80px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#080402', borderBottom: '1px solid #262626' }}>
            <div style={{ color: '#fff', fontWeight: 'bold', fontSize: '20px' }}>PasukanYerusSolo</div>

            <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
                {/* Menambahkan Link Home */}
                <Link to="/" style={{ color: '#fef3c7', textDecoration: 'none', fontWeight: 'bold' }}>Home</Link>

                <span 
                    onClick={() => setActiveMenu('eksplorasi')} 
                    style={{ color: activeMenu === 'eksplorasi' ? '#ea580c' : '#fef3c7', cursor: 'pointer', fontWeight: 'bold' }}
                >
                    Eksplorasi
                </span>

                {isAuthenticated ? (
                    <button onClick={handleLogout} style={{ background: '#ea580c', border: 'none', padding: '8px 16px', borderRadius: '8px', color: '#fff', cursor: 'pointer' }}>
                        Logout
                    </button>
                ) : (
                    <Link to="/login" style={{ color: '#fef3c7', textDecoration: 'none', fontWeight: 'bold' }}>Login</Link>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
